import{c as t,S as h,j as i,m as o}from"./chunks/framework.8aa1YH_s.js";const u=JSON.parse('{"title":"Cấu hình Hệ thống","description":"","frontmatter":{},"headers":[],"relativePath":"admin/he-thong.md","filePath":"admin/he-thong.md","lastUpdated":0}'),a={name:"admin/he-thong.md"};function l(e,n,r,g,c,s){return h(),i("div",null,[...n[0]||(n[0]=[o('<h1 id="cau-hinh-he-thong" tabindex="-1">Cấu hình Hệ thống <a class="header-anchor" href="#cau-hinh-he-thong" aria-label="Permalink to “Cấu hình Hệ thống”">​</a></h1><p>Nhóm <strong>Hệ thống</strong> chứa các cấu hình &quot;nền tảng&quot; mà admin cần thiết lập sớm và ít khi đụng vào sau đó.</p><table tabindex="0"><thead><tr><th>Mục</th><th>Đường dẫn</th><th>Mục đích</th></tr></thead><tbody><tr><td>Ngân hàng</td><td><code>https://lamsonedutech.vn/admin/system/bank</code></td><td>Tài khoản nhận tiền hiển thị cho học viên</td></tr><tr><td>Footer</td><td><code>https://lamsonedutech.vn/admin/system/footer</code></td><td>Nội dung phần chân trang website</td></tr><tr><td>Liên hệ</td><td><code>https://lamsonedutech.vn/admin/system/contact</code></td><td>Thông tin liên hệ, hotline, địa chỉ</td></tr></tbody></table><h2 id="_1-ngan-hang" tabindex="-1">1. Ngân hàng <a class="header-anchor" href="#_1-ngan-hang" aria-label="Permalink to “1. Ngân hàng”">​</a></h2><p>Mục này khai báo <strong>tài khoản ngân hàng nhận thanh toán</strong> mà học viên sẽ thấy khi thanh toán bằng chuyển khoản.</p><h3 id="tao-tai-khoan-ngan-hang" tabindex="-1">Tạo tài khoản ngân hàng <a class="header-anchor" href="#tao-tai-khoan-ngan-hang" aria-label="Permalink to “Tạo tài khoản ngân hàng”">​</a></h3><ol><li>Vào <code>https://lamsonedutech.vn/admin/system/bank</code> → bấm <strong>Thêm tài khoản</strong>.</li><li>Điền: <ul><li><strong>Tên ngân hàng</strong> (Vietcombank, BIDV, Techcombank, …)</li><li><strong>Chi nhánh</strong> (nếu cần)</li><li><strong>Số tài khoản</strong></li><li><strong>Chủ tài khoản</strong> (đúng như đăng ký với ngân hàng)</li><li><strong>Mã QR</strong> (tải lên ảnh, hoặc hệ thống tự sinh QR VietQR nếu hỗ trợ)</li><li><strong>Ưu tiên hiển thị</strong> (số thứ tự)</li><li><strong>Trạng thái</strong> (Bật / Tắt)</li></ul></li><li>Lưu.</li></ol><h3 id="hien-thi-cho-hoc-vien" tabindex="-1">Hiển thị cho học viên <a class="header-anchor" href="#hien-thi-cho-hoc-vien" aria-label="Permalink to “Hiển thị cho học viên”">​</a></h3><ul><li>Khi học viên chọn <strong>Thanh toán chuyển khoản</strong>, hệ thống hiển thị danh sách tài khoản đang bật.</li><li>Học viên copy thông tin hoặc quét QR để chuyển.</li><li>Sau khi chuyển, học viên có thể tải biên lai → admin xác nhận tại <a href="./hoa-don">Hóa đơn</a>.</li></ul><h3 id="luu-y" tabindex="-1">Lưu ý <a class="header-anchor" href="#luu-y" aria-label="Permalink to “Lưu ý”">​</a></h3><div class="warning custom-block"><p class="custom-block-title">Bảo mật</p><ul><li>Đảm bảo <strong>chủ tài khoản</strong> trùng pháp nhân/doanh nghiệp đang vận hành hệ thống.</li><li>Định kỳ đối soát với ngân hàng để kịp phát hiện giao dịch lạ.</li></ul></div><h2 id="_2-footer" tabindex="-1">2. Footer <a class="header-anchor" href="#_2-footer" aria-label="Permalink to “2. Footer”">​</a></h2><p>Footer là <strong>phần chân trang</strong> hiển thị trên mọi trang của website học viên.</p><h3 id="cac-phan-thuong-co-trong-footer" tabindex="-1">Các phần thường có trong footer <a class="header-anchor" href="#cac-phan-thuong-co-trong-footer" aria-label="Permalink to “Các phần thường có trong footer”">​</a></h3><ul><li>Logo + slogan</li><li>Cột &quot;Về chúng tôi&quot; (Giới thiệu, Liên hệ, Tuyển dụng)</li><li>Cột &quot;Pháp lý&quot; (Điều khoản sử dụng, Chính sách bảo mật, Bảo mật thanh toán)</li><li>Cột &quot;Hỗ trợ&quot; (FAQ, Hướng dẫn, Hotline)</li><li>Mạng xã hội (Facebook, YouTube, Zalo, TikTok)</li><li>Đăng ký nhận tin</li><li>Bản quyền</li></ul><h3 id="cau-hinh-footer" tabindex="-1">Cấu hình Footer <a class="header-anchor" href="#cau-hinh-footer" aria-label="Permalink to “Cấu hình Footer”">​</a></h3><ol><li>Vào <code>https://lamsonedutech.vn/admin/system/footer</code>.</li><li>Mỗi <strong>cột</strong> trong footer là 1 nhóm: <ul><li>Tiêu đề cột (vd &quot;Liên hệ&quot;)</li><li>Danh sách link (text + URL)</li></ul></li><li>Có khu vực <strong>HTML tự do</strong> cho phần copyright hoặc nội dung khác.</li><li>Lưu → hệ thống cập nhật ngay trên trang chủ.</li></ol><h2 id="_3-lien-he" tabindex="-1">3. Liên hệ <a class="header-anchor" href="#_3-lien-he" aria-label="Permalink to “3. Liên hệ”">​</a></h2><p>Thông tin liên hệ chính của tổ chức.</p><h3 id="truong-thong-tin" tabindex="-1">Trường thông tin <a class="header-anchor" href="#truong-thong-tin" aria-label="Permalink to “Trường thông tin”">​</a></h3><ul><li>Tên đơn vị / Doanh nghiệp</li><li>Địa chỉ (chính, chi nhánh)</li><li>Hotline (1 hoặc nhiều)</li><li>Email hỗ trợ</li><li>Email tuyển dụng</li><li>Giờ làm việc</li><li>Bản đồ Google Map (nhúng iframe hoặc tọa độ)</li><li>Liên kết mạng xã hội</li></ul><h3 id="cap-nhat" tabindex="-1">Cập nhật <a class="header-anchor" href="#cap-nhat" aria-label="Permalink to “Cập nhật”">​</a></h3><ol><li>Vào <code>https://lamsonedutech.vn/admin/system/contact</code>.</li><li>Sửa từng trường → Lưu.</li><li>Thông tin sẽ hiển thị tự động ở: <ul><li>Trang <strong>Liên hệ</strong> trên website.</li><li>Footer (nếu cấu hình).</li><li>Email tự động gửi cho học viên.</li></ul></li></ol><h2 id="cau-hoi-thuong-gap" tabindex="-1">Câu hỏi thường gặp <a class="header-anchor" href="#cau-hoi-thuong-gap" aria-label="Permalink to “Câu hỏi thường gặp”">​</a></h2><p><strong>Đổi logo footer thì làm ở đâu?</strong> → Có thể trong Footer hoặc Cấu hình thương hiệu (tùy phiên bản hệ thống). Liên hệ IT nếu không tìm thấy.</p><p><strong>Tài khoản ngân hàng cũ vẫn hiển thị dù đã tắt?</strong> → Có thể do cache. Yêu cầu học viên reload trang.</p><p><strong>Cần thêm điều khoản pháp lý dài (vd Chính sách bảo mật).</strong> → Tạo 1 trang riêng (Page) trong <strong>Banner → Menu</strong> hoặc nhờ IT bổ sung route, sau đó trỏ link footer tới trang đó.</p>',27)])])}const m=t(a,[["render",l]]);export{u as __pageData,m as default};
